    public int lcs(String s1, String s2) {

        // Get sizes
        int n = s1.length();
        int m = s2.length();

        // Initialize prev and cur rows
        int[] prev = new int[m + 1];
        int[] cur = new int[m + 1];

        // Fill rows
        for (int ind1 = 1; ind1 <= n; ind1++) {
            for (int ind2 = 1; ind2 <= m; ind2++) {

                // If characters match
                if (s1.charAt(ind1 - 1) == s2.charAt(ind2 - 1))
                    cur[ind2] = 1 + prev[ind2 - 1];

                // Else take max from prev row or left
                else
                    cur[ind2] = Math.max(prev[ind2], cur[ind2 - 1]);
            }

            // Move cur to prev
            prev = cur.clone();
        }

        // Return result
        return prev[m];
    }

    // Function to compute LPS
    public int longestPalindromeSubsequence(String s) {
        StringBuilder sb = new StringBuilder(s);
        sb.reverse();
        String t = sb.toString();
        return lcs(s, t);
    }

    // Function to compute min insertions
    public int minInsertion(String s) {
        int n = s.length();
        int k = longestPalindromeSubsequence(s);
        return n - k;
    }
}

public class Main {
    public static void main(String[] args) {
        Solution sol = new Solution();
        String s = "abcaa";
        System.out.println(
            "The Minimum insertions required to make string palindrome: " 
            + sol.minInsertion(s)
        );
    }
}

